/* ============================================================
   ENCABEZADOS DE LA TABLA — alineados + border continuo
   ============================================================ */

/* Wrapper del encabezado: expande al ancho COMPLETO del row interno
   para que el border-bottom cubra todo sin cortarse */
[selector="Encabezado-in-table"] {
  display: block;
  min-width: max-content;
  border-bottom: 3px solid #2167AE;
  margin-top: 18px;
  margin-bottom: 18px;
  padding-bottom: 8px;
}

/* Row interno del encabezado: nowrap y ancho real */
[selector="Encabezado-in-table"] > .row {
  flex-wrap: nowrap;
  min-width: max-content;
  align-items: stretch;       /* todas las columnas a la misma altura */
  margin-left: 0;
  margin-right: 0;
}

/* CADA columna del encabezado: flex para centrar vertical y horizontalmente */
[selector="Encabezado-in-table"] > .row > [class*="col-sm-"] {
  display: flex !important;
  flex-direction: column;
  justify-content: center;    /* centrado vertical */
  align-items: center;        /* centrado horizontal */
  min-height: 80px;           /* misma altura mínima en todos */
  padding: 10px 6px;
}

/* Texto del encabezado */
[selector="Encabezado-in-table"] p {
  margin: 0;
  color: #2167AE;
  line-height: 1.2;
  text-align: center;
  font-weight: 500;
}

/* Bordes redondeados en las columnas extremas */
[selector="Encabezado-in-table"] > .row > [class*="col-sm-"]:first-child {
  border-top-left-radius: 12px;
}
[selector="Encabezado-in-table"] > .row > [class*="col-sm-"]:last-child {
  border-top-right-radius: 12px;
}




/* ============================================================
   BODY-IN-TABLE — centrado de celdas
   ============================================================ */

[selector="Body-in-table"] > .row > [class*="col-sm-"] {
  display: flex !important;
  flex-direction: column;
  justify-content: center;    /* centrado vertical */
  align-items: center;        /* centrado horizontal */
}



























[selector="docs-upload"] {
  display: block;
  padding-bottom: 20px;
  color: #1f2937;
}


[selector="docs-upload"] .required-asterisk {
  color: #dc2626;
  margin-right: .25rem;
  font-weight: 700;
}

[selector="docs-upload"] .invalid-feedback {
  margin-top: .5rem;
  font-size: .9rem;
  color: #dc2626;
}

[selector="docs-upload"] > label {
  display: inline-block;
  font-weight: 600;
  margin-bottom: .5rem;
  color: #1f2937;
}

[selector="docs-upload"] .uploader .form-control-file {
  position: relative;
  display: grid;
  place-items: center;
  
  min-height: 140px;
  padding: 8px;
  border: 2px dashed #d6e3f3;
  border-radius: 16px;
  margin-top: 12px;
  transition: border-color .2s ease, background-color .2s ease, transform .12s ease;
  text-align: center;
}

[selector="docs-upload"] .form-control-file > p {
  margin: 0;
  font-size: .95rem;
  color: #64748b;
}

[selector="docs-upload"] .form-control-file::before {
  content: "\f574"; /* fa-file-upload */
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  font-size: 2.25rem;
  line-height: 1;
  color: #16a34a;
  opacity: .9;
}

/* Estado focus/hover con verde suave */
[selector="docs-upload"] .uploader .form-control-file:focus-within,
[selector="docs-upload"] .uploader .form-control-file:hover {
  border: 2px solid #86efac;   
  background: #dcfce7;        
  transform: translateY(-1px);
  box-shadow: 0 6px 16px rgba(22,163,74,.15);
}

[selector="docs-upload"] .form-control-file .btn {
  border: 1px solid #16a34a;
  background: #16a34a;
  color: #ffffff !important;
  padding: .5rem .9rem;
  border-radius: 999px;
  line-height: 1.1;
  transition: transform .12s ease, opacity .2s ease, box-shadow .2s ease;
  text-transform: none;
  font-weight: 600;
}
[selector="docs-upload"] .form-control-file .btn:hover {
  transform: translateY(-1px);
  box-shadow: 0 6px 16px rgba(22,163,74,.30);
  opacity: .95;
}

[selector="docs-upload"] .uploader-list ul {
  list-style: none;
  margin: 14px 0 0;
  padding: 0;
  display: grid;
  gap: 10px;
}

[selector="docs-upload"] .uploader-list li > div > div {
  border-radius: 14px !important;
  background: #ffffff !important;
  border: 1px solid #d6e3f3;
  padding: 14px 14px 16px !important; 
  align-items: center;
}

[selector="docs-upload"] .uploader-file {
  position: relative;
  padding: 12px 0 2px;
}
[selector="docs-upload"] .uploader-file-info {
  align-items: center;
  margin-top: -9px;
}
[selector="docs-upload"] .uploader-file-name {
  font-weight: 600;
  color: #1f2937;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
[selector="docs-upload"] .uploader-file-name .uploader-file-icon {
  margin-right: .5rem;
  opacity: .9;
}
[selector="docs-upload"] .uploader-file-size,
[selector="docs-upload"] .uploader-file-status span {
  color: #64748b;
  font-size: .85rem;
}

[selector="docs-upload"] .uploader-file-progress {
  position: absolute;
  top: 0;
  left: 0;
  height: 6px;
  border-radius: 8px 8px 0 0;
  background: linear-gradient(90deg, #16a34a, #22c55e);
  transition: transform .25s ease;
}

/*
[selector="docs-upload"] .uploader-file-actions {
  display: inline-flex;
  gap: 14px;
  align-items: center;
}
*/

[selector="docs-upload"] .uploader-file-actions{
  display: none;
}

[selector="docs-upload"] .uploader-file-remove,
[selector="docs-upload"] .uploader-file-retry,
[selector="docs-upload"] .uploader-file-pause,
[selector="docs-upload"] .uploader-file-resume {
  width: 28px;
  height: 28px;
  display: inline-grid;
  place-items: center;
  border-radius: 8px;
  cursor: pointer;
  transition: background-color .2s ease, transform .12s ease, color .2s ease;
}

[selector="docs-upload"] .uploader-file-retry:hover,
[selector="docs-upload"] .uploader-file-resume:hover,
[selector="docs-upload"] .uploader-file-pause:hover {
  background: rgba(22,163,74,.08);
  color: #16a34a;
  transform: translateY(-1px);
}
/* */
[selector="docs-upload"] .uploader-file-remove:hover {
  background: rgba(220,38,38,.08);
  color: #dc2626;
  transform: translateY(-1px);
}

[selector="docs-upload"] .uploader-list .btn.btn-outline {
  border-color: #d6e3f3;
  background: #ffffff;
  color: #dc2626; 
  border-radius: 10px;
  margin-left: 10px;
  transition: all .2s ease;
}

[selector="docs-upload"] .uploader-list .btn.btn-outline i,
[selector="docs-upload"] .uploader-list .btn.btn-outline .fas,
[selector="docs-upload"] .uploader-list .btn.btn-outline .fa-solid,
[selector="docs-upload"] .uploader-list .btn.btn-outline .fa {
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  color: #dc2626;                     
  font-size: 1rem;
  line-height: 1;
  display: inline-block;
}
[selector="docs-upload"] .uploader-list .btn.btn-outline:hover {
  border-color: #dc2626;
  background: rgba(220,38,38,.06);
  color: #b91c1c;
}

[selector="docs-upload"] .uploader-list .btn.btn-outline i:empty::before {
  content: "\f2ed"; 
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  color: #dc2626;
}


[selector="docs-upload"] .uploader.was-validated .form-control-file {
  border-color: #86efac; /* borde verde al validar */
}

[selector="docs-upload"] .form-control-file .btn:focus,
[selector="docs-upload"] .uploader-file-remove:focus,
[selector="docs-upload"] .uploader-file-retry:focus {
  outline: none;
  box-shadow: 0 0 0 3px rgba(22,163,74,.35);
}

@media (max-width: 575.98px) {
  [selector="docs-upload"] .uploader .form-control-file {
    min-height: 120px;
    padding: 14px;
  }
  [selector="docs-upload"] .uploader-file-info {
    grid-template-columns: 1fr;
    gap: 6px;
  }
}


[selector="docs-upload"] .uploader-file-status > span:first-child{
  position: relative;
  color: transparent;   
  font-size: 0;   
}

[selector="docs-upload"] .uploader-file-status > span:first-child::after{
  content: "Cargado";
  color: #64748b;
  font-size: .85rem;
}










/* =========================
   TABS Zurich (sin scroll)
   Colores:
   - Base suave: #91bfe3
   - Normal (texto): #0f4c81
   - Active (texto + underline): #2167AE
   ========================= */
[selector="tab"] .row{
  margin: 0px 12px !important;
  display: flex !important;
  flex-wrap: nowrap !important;
  align-items: center;
  gap: 1.6rem;

  /* línea base */
  border-bottom: 2px solid #91bfe3;

  padding: 0 .75rem;

  /* ancho del underline (ajústalo) */
  --ul-w-hover: 85%;
  --ul-w-active: 90%;
}

/* Quitar overflow que genera scroll */
[selector="tab"] .row,
[selector="tab"] .row *{
  overflow: visible !important;
}

[selector="tab"] .form-group{
  margin: 0 !important;
  max-height: none !important;
}

/* Quitar gutters */
[selector="tab"] .row > [class*="col-"]{
  padding-left: 0 !important;
  padding-right: 0 !important;
}

/* Botón tipo tab */
[selector="tab"] .form-group > .btn.btn-primary{
  width: 100%;
  background: transparent !important;
  border: 0 !important;
  box-shadow: none !important;
  border-radius: 0 !important;

  /* normal Zurich */
  color: #0f4c81 !important;
  font-weight: 500;
  font-size: 1.05rem;

  /* para que el underline se “pegue” al borde inferior del contenedor */
  display: inline-flex;
  align-items: center;
  justify-content: center;

  padding: .75rem 0 .85rem;
  position: relative;
  transition: color .15s ease;
}

/* Underline: alineado EXACTO sobre la línea base */
[selector="tab"] .form-group > .btn.btn-primary::after{
  content: "";
  position: absolute;
  left: 50%;
  transform: translateX(-50%);

  /* clave: la base mide 2px, entonces lo bajo 2px para que quede encima exacto */
  bottom: -2px;

  height: 4px;
  width: 0;                 /* oculto por defecto */
  background: #0f4c81;      /* normal underline */
  transition: width .18s ease, background-color .15s ease;
}

/* Hover */
[selector="tab"] .form-group > .btn.btn-primary:hover{
  color: #0f4c81 !important;
}
[selector="tab"] .form-group > .btn.btn-primary:hover::after{
  width: var(--ul-w-hover);
  background: #0f4c81;
}

/* ACTIVE (3 posibles estados) */
[selector="tab"] .form-group > .btn.btn-primary.active,
[selector="tab"] .form-group[selected="selected"] > .btn.btn-primary,
[selector="tab"] .form-group[aria-selected="true"] > .btn.btn-primary{
  color: #2167AE !important;
  font-weight: 700;
}

[selector="tab"] .form-group > .btn.btn-primary.active::after,
[selector="tab"] .form-group[selected="selected"] > .btn.btn-primary::after,
[selector="tab"] .form-group[aria-selected="true"] > .btn.btn-primary::after{
  width: var(--ul-w-active);  /* <-- aquí regulas el ancho del active */
  background: #2167AE;        /* active underline */
}

/* Focus sin glow */
[selector="tab"] .form-group > .btn:focus,
[selector="tab"] .form-group > .btn:active{
  outline: none !important;
  box-shadow: none !important;
}


/* =========================
   ACTIVE por selector="tab-active"
   (si existe ese wrapper, ese tab queda como seleccionado)
   ========================= */
[selector="tab"] [selector="tab-active"] .form-group > .btn.btn-primary{
  color: #2167AE !important;
  font-weight: 700 !important;
}

[selector="tab"] [selector="tab-active"] .form-group > .btn.btn-primary::after{
  width: var(--ul-w-active) !important;
  background: #2167AE !important;
}


/* ==========================
   CONTENEDOR: Previous + Next en la MISMA FILA
   ========================== */

[selector="buttons-previous-next"] .col-sm-12{
  display: flex !important;
  justify-content: flex-start !important;  /* los manda a la derecha */
  align-items: center !important;
  gap: 10px;                             /* separación entre botones */
  margin: 18px 10px;
}

/* Evita scroll raro por overflow interno */
[selector="buttons-previous-next"] .form-group{
  margin: 0 !important;
  overflow: visible !important;
}

/* Ambos wrappers ya NO deben ocupar 100% */
[selector='button-previous'],
[selector='button-next']{
  width: auto !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  margin: 0 !important;
}

[selector='button-previous'] > div,
[selector='button-next'] > div{
  width: auto !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
}

/* ==========================
   BOTONES (mismo estilo)
   ========================== */

[selector='button-previous'] button.btn-primary,
[selector='button-next'] button.btn-primary{
  position: relative;
  display: inline-flex !important;
  align-items: center;
  justify-content: center;

  /* Tamaño tipo icon-button */
  width: 38px;
  height: 34px;
  padding: 0 !important;

  background-color: #2167AE !important;
  color: #fff !important;
  border: 1px solid #2167AE !important;
  border-radius: 8px;
  font-size: 18px;       /* hace la flecha más visible */
  font-weight: 700;
  line-height: 1;
  cursor: pointer;

  transition: background-color 0.2s ease, color 0.2s ease, box-shadow 0.2s ease;
}

/* QUITAR EL OJO (el pseudo elemento) */
[selector='button-previous'] button.btn-primary::before,
[selector='button-next'] button.btn-primary::before{
  content: none !important;
  display: none !important;
}

/* Hover */
[selector='button-previous'] button.btn-primary:hover,
[selector='button-next'] button.btn-primary:hover{
  background-color: #fff !important;
  color: #2167AE !important;
  border-color: #2167AE !important;
}

/* ==========================
   DISABLED: Previous / Next
   (mismo tamaño, gris #728092)
   ========================== */

/* Wrapper disabled (por si quieres mantener la misma fila) */
[selector="button-previous-next-disabled"]{
  width: auto !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  margin: 0 !important;
}

[selector="button-previous-next-disabled"] > div{
  width: auto !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
}

/* Botón gris */
[selector="button-previous-next-disabled"] button.btn-primary{
  width: 38px;
  height: 34px;
  padding: 0 !important;

  background-color: #728092 !important;
  border: 1px solid #728092 !important;
  color: #fff !important;

  border-radius: 8px;
  font-size: 18px;
  font-weight: 700;
  line-height: 1;

  cursor: not-allowed !important;
  opacity: 0.85;                 /* look disabled */
  pointer-events: none !important; /* no clic */
}

/* Asegurar que no aparezca el "ojo" */
[selector="button-previous-next-disabled"] button.btn-primary::before{
  content: none !important;
  display: none !important;
}

/* Sin hover (se queda gris) */
[selector="button-previous-next-disabled"] button.btn-primary:hover{
  background-color: #728092 !important;
  border-color: #728092 !important;
  color: #fff !important;
}










/* Fondo blanco semitransparente que cubre toda la pantalla */
#global-loader-overlay-generar-pricing {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  background: rgba(255, 255, 255, 0.75);
  z-index: 9999;
  display: none;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

/* Mostrar el loader */
#global-loader-overlay-generar-pricing.show {
  display: flex;
}

/* Fondo blanco semitransparente que cubre toda la pantalla */
#global-loader-overlay-nueva-opcion {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  background: rgba(255, 255, 255, 0.75);
  z-index: 9999;
  display: none;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

/* Mostrar el loader */
#global-loader-overlay-nueva-opcion.show {
  display: flex;
}


/* Fondo blanco semitransparente que cubre toda la pantalla */
#global-loader-overlay-terminos-condiciones-slip {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  background: rgba(255, 255, 255, 0.75);
  z-index: 9999;
  display: none;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

/* Mostrar el loader */
#global-loader-overlay-terminos-condiciones-slip.show {
  display: flex;
}

/* Spinner circular con color corporativo */
#global-loader-spinner {
  width: 60px;
  height: 60px;
  border: 6px solid #e0e0e0;
  border-top: 6px solid #2167AE;
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

/* Animación */
@keyframes spin {
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}




/* bar-tip */
[selector="ObservacionRichText-SpacingBottom"] {
  display:block;
  width:100%;
}

[selector="ObservacionRichText-SpacingBottom"] .form-group > div > div {
  display:flex;                 /* icono + texto en fila */
  gap:2px;
  align-items:flex-start;
  background:#fff7e6;           
  border-left:4px solid #ffb020;
  padding:12px 14px;
  border-radius:8px;
  box-shadow:0 1px 2px rgba(0,0,0,.06);
}

[selector="ObservacionRichText-SpacingBottom"] .form-group > div > div::before {
  content:"\f06a";              /* fa-exclamation-circle */
  font-family:"Font Awesome 5 Free","Font Awesome 6 Free";
  font-weight:900;
  font-size:16px;
  line-height:1.2;
  flex:0 0 auto;
  margin-top:2px;
  color:#b35c00;
}

[selector="ObservacionRichText-SpacingBottom"] p {
  display:block;
  margin:0;
  color:#333;
  font-size: 15px;
}

[selector="ObservacionRichText-SpacingBottom"] p strong {
  font-weight:700;
  color:#8a4d00;
  font-size: 15px;
}

/* Espacio vertical respecto al bloque de arriba */
[selector="ObservacionRichText-SpacingBottom"] .form-group {
  margin-top:12px;
  margin-bottom: 12px;
}
